SELECT year, water_quality_index AS highest_water_quality_index
FROM yearly_data
WHERE year BETWEEN 2000 AND 2010;

SELECT total_consumption
FROM water_consumption
WHERE year = 2010;

SELECT year, budget
FROM infrastructure
ORDER BY year ASC;

SELECT AVG(budget) as average_budget
FROM water_conservation
WHERE year = 2019;

SELECT YEAR, TOTAL_CONSUMPTION, AVERAGE_CONSUMPTION_PER_CAPITA
FROM water_consumption
WHERE YEAR IN (2018, 2019, 2020);

SELECT MAX(water_quality_index) AS peak_water_quality
FROM yearly_data
WHERE year = 2010;

SELECT annual_rainfall
FROM rainfall_records
WHERE year > 1 AND drought_duration > 100;

SELECT year
FROM yearly_data
WHERE water_consumption = (SELECT MAX(water_consumption) FROM yearly_data);

SELECT year 
FROM water_consumption 
WHERE commercial_consumption = (SELECT MAX(commercial_consumption) FROM water_consumption);

SELECT year, population, price_per_m3, annual_rainfall, water_consumption
FROM yearly_data
WHERE year > 2000 AND water_consumption > 400000 AND population > 400000;

SELECT year, SUM(budget) AS total_budget
FROM water_conservation
GROUP BY year;

SELECT y.year, w.total_consumption / y.population AS consumption_per_capita
FROM yearly_data y
JOIN water_consumption w ON y.year = w.year;

SELECT year, average_consumption_per_capita
FROM water_consumption
ORDER BY year ASC;

SELECT initiative_id, year, impact
FROM water_conservation
WHERE impact IS NOT NULL;
